                lines = [l.strip() for l in re.sub(r'<[^>]+>', '\n', jhtml).splitlines() if l.strip()]
                for l in lines:
                    if any(k in l.lower() for k in ["error", "exception", "failed", "unresolved", "kapt", "task"]):
